  {"id": "US-014", "title": "404 Not Found Page", "description": "Build custom 404 page (app/not-found.tsx) with terminal-style error display (404 ERROR: Page not found in monospace), friendly message Aradiginiz sayfa bulunamadi., illustration or error graphic, navigation suggestions (quick links to main pages), recent blog posts (2-3 items), search suggestion to use command palette. Design matches dark theme with primary accent. Fully animated entrance.", "acceptanceCriteria": ["Terminal-style header: 404 ERROR: Page not found in JetBrains Mono, text-primary", "Message: text-secondary text-lg", "Quick navigation links: Ana Sayfa, Projeler, Blog, Hakkinda, Iletisim (same style as footer links)", "Recent blog posts section: 2-3 cards with thumbnail + title + excerpt", "Search suggestion: Aramadiginiz sayfa Cmd+K kullanin with command palette icon", "Illustration: error-themed graphic or emoji", "Animation: fade-in on load, staggered elements", "Matches dark theme: bg-background, text-primary/secondary accents", "Typecheck passes", "Tests for 404 page pass"], "depends_on": ["US-004", "US-005", "US-006", "US-009"], "screens": []},
  {"id": "US-015", "title": "Contact API Route", "description": "Build POST /api/contact Next.js Route Handler. Accepts ContactFormData: firstName, lastName, email, subject, message. Validates all fields server-side (same rules as client: firstName/lastName 2-50 letters, email valid format, subject 5-200, message 20-2000). Rate limiting: 5 requests per hour per IP. Returns 201 with success id on success, 400 with validation errors, 429 on rate limit, 500 on server error. Logs submissions. In production-ready structure for future email service integration (Resend/SendGrid).", "acceptanceCriteria": ["POST /api/contact handler in app/api/contact/route.ts", "Request body validated: firstName lastName 2-50 letters-only, email valid format, subject 5-200 chars, message 20-2000 chars", "Success response: 201 { success: true, id: string (uuid), timestamp: string }", "Validation error response: 400 { success: false, error: { code: string, message: string, details: Record<string, string> } }", "Rate limit: 5 requests/hour/IP, returns 429 with Retry-After header", "Server error: 500 { success: false, error: { code: string, message: string } }", "CORS headers for same-origin", "Request logging: console.log form submission (structured)", "Export type ContactSubmission from handler for future persistence", "Structure ready for email service integration", "Typecheck passes", "Tests for contact API pass"], "depends_on": ["US-003"], "screens": []},
